INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0c700c30-moex-00088', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「農業部澄清，全國遊蕩犬隻控制減量的重要方法，是以科學化、系統性模式，由縣市政府 按村里建立轄內遊蕩犬與野生動物保育衝突熱區，集中資源於熱區內全面逐戶清查處置，家 犬全數寵物登記、實施繁殖管理與不放養，善盡飼主責任；無主犬隻則視狀況進行捕捉、絕 育與回置，有公安等問題無法回置時則將犬隻收容管理，踏實穩健進行遊蕩犬控制工作。」 根據上文，下列選項正確的是：', '["農業部控制遊蕩犬隻數量的方法，包括絕育而非撲殺", "因犬隻與野生動物常襲擊民眾，故設定保育衝突熱區", "飼主應對家犬進行寵物登記，並且不隨意放養或繁殖", "無主犬隻在特殊狀況下，仍有可能對其進行捕捉收容 農業部以科學化且系統性的模式，讓遊蕩犬得到收養"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00089', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「四月五，烏沉香插遍山崗古墓。彎形鐮刀只斬五節芒、爬墓藤，不斬家國血脈。數百年來 滄桑渡海，何曾畏懼狂浪噬舟？縱使船破人浮，猶掌握一線香袋不容盡濕，遂扶老攜幼，家 祠南來。」 根據上文，下列選項正確的是：', '["描寫清明節的掃墓活動", "慎終追遠是不可或忘的文化傳統", "「掌握一線香袋」意指配戴廟宇祈求的平安符", "「數百年來滄桑渡海」是形容祖先為了謀生，拋家棄子獨自來到異鄉 祖先為了謀生離鄉背井，無論是替人整理墓地，或是冒險捕魚的工作都願意做"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00090', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '古之君子有所為、有所不為，即使處於逆境，仍能堅守節操，不同流合汙。 根據上文，下列選項何者符合文意？', '["時窮節乃見，一一垂丹青", "舉世皆濁我獨清，眾人皆醉我獨醒", "使其中坦然不以物傷性，將何適而非快", "吾不能變心而從俗兮，固將愁苦而終窮 君子之所取者遠，則必有所待；所就者大，則必有所忍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00091', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「番薯是原產於拉丁美洲的作物。日文裡的番薯稱為『薩摩芋』，意即來自薩摩地區，這個 稱呼主要在日本的本州以北使用，在北九州則有『琉球芋』之稱，可是南九州、沖繩又以『唐 芋』稱呼。同樣在中國，浙東地區士大夫編纂地方誌時，就舉出『番芋』是舟山群島的特產 之一，並在說明『味甚甘美』的同時，也記載了『種來自日本』，而番薯的『番』是指日本。」 根據上文，下列選項何者符合文意？', '["番薯雖原產於拉丁美洲，但在亞洲成為重要的主食", "日本的本州與南北九州，對番薯有三種不同的稱呼", "沖繩對番薯的說法差異，主要是受到經濟文化影響", "人們對番薯的各種稱呼，反映對其來源的不同看法 番薯應是舟山群島特產，但中國士人以為來自日本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00092', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '古人曾言「所種者穀，雖瘠土墮農，不生稗也；所種者稗，雖美田疾耕，不生穀也。」 根據上文，下列選項何者符合文意？', '["水到渠成，不須預慮", "江山易改，本性難移", "種瓜得瓜，種豆得豆", "貧不學儉，富不學奢 蓬生麻中，不扶自直"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00093', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '落日千林紫，漁舟聚淺灘。飛蓬雲外沒，野鳥望中還。寺小藏深樹，潮寬點亂山。一樽頻對 此，無意羨人間。（宋懋澄〈晚色〉） 根據上詩，下列敘述何者正確？', '["刻畫景物，藉景抒情", "蘊含瀟灑的出世之想", "充滿山水意趣，富有情韻", "描寫晚景，宛如一幅山水畫卷 近似「夕陽無限好，只是近黃昏」之意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00094', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「畫家在素描時，勒定了所畫對象大約的輪廓後，只以炭筆磨擦出光影的陰暗與明亮，而不 做細部的描繪，保持一點朦朧感，以免整個畫面過於呆板。這個階段，就像詩一樣，在光與 暗、有與無之間，帶著一點迷濛，一點神祕，一點耐人追索的況味。然而這並非脫離現實， 仔細想想，我們在人生裡，大多數的情感都是這樣迷濛的吧！誰能肯定自己的內心無論是哪 一刻都清晰無比的呢？」 根據上文，下列選項正確的是：', '["擅長讀詩的人擁有最單純的心思，對世事經常感到懵懵懂懂", "詩在指涉、內涵上的模糊性，常能帶給讀者解釋探索的趣味", "詩與素描一樣，都不可進行細部描繪，才能提升整體的美感", "思緒清明的人難以享受讀詩之樂，因複雜處能輕易迎刃而解 生命中多數情感一如詩般迷濛，從詩中可以體會人生與現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00095', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00096', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-932665b2', 'sub-elementary-0c700c30-03', NULL, 'single_choice', '若 、 為兩隨機變數，下列敘述何者錯誤？', '["若X、Y互相獨立，則 0", "若Cov(X,Y)0，則X，Y互相獨立   XY", "若X、Y互相獨立，則E(XY)E(X)E(Y)", "若X、Y互相獨立，則Cov(X,Y)0"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "d5ca6374d984", "answer_pdf_sha1": "e8775a1d784c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "統計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00097', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-932665b2', 'sub-elementary-0c700c30-03', NULL, 'single_choice', '某位候選人之團隊想了解該候選人之當選率，於是在電話號碼簿中，每隔 1,000 名取一名為調查樣 本，此抽樣方法為：', '["分層抽樣法", "集體抽樣法", "系統抽樣法", "立意抽樣法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "d5ca6374d984", "answer_pdf_sha1": "e8775a1d784c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "統計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
